$output=Join-Path $root "output"
$meta=@'
{"01_sorting_problem": {"title": "01 Sorting Problem", "topic": "Sorting Problem 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 input records to ordered output。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 01_sorting_problem.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Sorting Problem 的完整流程。"}, "02_inplace_stable_sorting": {"title": "02 In-place and Stable Sorting", "topic": "In-place and Stable Sorting 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 memory and equal-key order。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 02_inplace_stable_sorting.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 In-place and Stable Sorting 的完整流程。"}, "03_internal_external_sorting": {"title": "03 Internal vs External Sorting", "topic": "Internal vs External Sorting 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 memory vs storage sorting。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 03_internal_external_sorting.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Internal vs External Sorting 的完整流程。"}, "04_comparison_sort_overview": {"title": "04 Comparison Sort Overview", "topic": "Comparison Sort Overview 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 pairwise key comparison。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 04_comparison_sort_overview.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Comparison Sort Overview 的完整流程。"}, "05_bubble_sort": {"title": "05 Bubble Sort", "topic": "Bubble Sort 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 swap adjacent inversions。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 05_bubble_sort.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Bubble Sort 的完整流程。"}, "06_selection_sort": {"title": "06 Selection Sort", "topic": "Selection Sort 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 select minimum each pass。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 06_selection_sort.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Selection Sort 的完整流程。"}, "07_insertion_sort": {"title": "07 Insertion Sort", "topic": "Insertion Sort 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 insert into sorted prefix。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 07_insertion_sort.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Insertion Sort 的完整流程。"}, "08_quick_sort_partition": {"title": "08 Quick Sort Partition", "topic": "Quick Sort Partition 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 split around pivot。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 08_quick_sort_partition.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Quick Sort Partition 的完整流程。"}, "09_quick_sort_recursion": {"title": "09 Quick Sort Recursion", "topic": "Quick Sort Recursion 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 recursive divide and conquer。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 09_quick_sort_recursion.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Quick Sort Recursion 的完整流程。"}, "10_decision_tree_lower_bound": {"title": "10 Decision Tree Lower Bound", "topic": "Decision Tree Lower Bound 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 comparison lower bound。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 10_decision_tree_lower_bound.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Decision Tree Lower Bound 的完整流程。"}, "11_iterative_merge_sort": {"title": "11 Iterative Merge Sort", "topic": "Iterative Merge Sort 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 bottom-up runs。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 11_iterative_merge_sort.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Iterative Merge Sort 的完整流程。"}, "12_merge_operation": {"title": "12 Merge Operation", "topic": "Merge Operation 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 two-pointer merge。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 12_merge_operation.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Merge Operation 的完整流程。"}, "13_recursive_merge_sort": {"title": "13 Recursive Merge Sort", "topic": "Recursive Merge Sort 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 split and merge。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 13_recursive_merge_sort.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Recursive Merge Sort 的完整流程。"}, "14_sorting_summary": {"title": "14 Sorting Summary", "topic": "Sorting Summary 是 lec7 Sorting 的重要主題。這個主題用排序問題的角度說明 compare algorithms。學習時要注意：資料項目 record 可能包含很多欄位，但排序依據通常是 key；不同演算法會用不同方式比較、交換、選取、插入、分割或合併資料；考試常要求手算每一回合的陣列狀態，也常比較時間複雜度、穩定性與是否 in-place。", "anim": "本動畫由 C++ 程式 14_sorting_summary.cpp 直接輸出多張 step_XX.svg，PowerShell 只負責掃描 output 目錄並產生 HTML 播放器。紅色區塊或箭頭表示目前正在處理的比較、移動或確認步驟；綠色代表已完成區域；藍色代表尚未固定的背景資料。使用上一張、下一張可以逐格檢查，使用自動播放可以觀察 Sorting Summary 的完整流程。"}}
'@ | ConvertFrom-Json
$css=@'
body{font-family:Arial,'Microsoft JhengHei',sans-serif;background:#f3f7fb;margin:0;color:#102030}header{background:#17324d;color:white;padding:24px 36px}main{padding:22px}.topic{background:white;border:1px solid #c8d8e8;border-radius:12px;margin:18px 0;overflow:hidden}summary{font-size:24px;font-weight:800;padding:18px 24px;background:#eaf4ff;cursor:pointer}.desc{margin:16px 24px;padding:16px 20px;background:#fff9e6;border-left:6px solid #e0a800;border-radius:10px;line-height:1.8}.anim{background:#eef9ff;border-left-color:#2f78c4}.player{margin:20px 24px}.controls{display:flex;gap:12px;align-items:center;flex-wrap:wrap;margin-bottom:14px}button,select{font-size:16px;padding:8px 12px;border-radius:8px;border:1px solid #8baed0;background:white}.frame{width:100%;max-width:1140px;border:1px solid #c8d8e8;border-radius:10px;background:white;display:block}.grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(300px,1fr));gap:16px;margin:20px 24px}.grid img{width:100%;border:1px solid #c8d8e8;border-radius:8px}figcaption{font-size:13px;word-break:break-all}
'@
$js=@'
document.querySelectorAll('.player').forEach(p=>{const frames=JSON.parse(p.dataset.frames);let i=0,t=null;const img=p.querySelector('.frame'),c=p.querySelector('.counter'),sp=p.querySelector('.speed'),pl=p.querySelector('.play');function show(){img.src=frames[i];c.textContent=(i+1)+' / '+frames.length;}p.querySelector('.next').onclick=()=>{i=(i+1)%frames.length;show();};p.querySelector('.prev').onclick=()=>{i=(i-1+frames.length)%frames.length;show();};pl.onclick=()=>{if(t){clearInterval(t);t=null;pl.textContent='自動播放';}else{t=setInterval(()=>{i=(i+1)%frames.length;show();},parseInt(sp.value));pl.textContent='停止播放';}};sp.onchange=()=>{if(t){clearInterval(t);t=setInterval(()=>{i=(i+1)%frames.length;show();},parseInt(sp.value));}};show();});
'@
$sections="";$static=""
Get-ChildItem $output -Directory | Sort-Object Name | ForEach-Object { $d=$_; $stem=$d.Name -replace "_steps$",""; $info=$meta.$stem; $files=Get-ChildItem $d.FullName -Filter "step_*.svg" | Sort-Object Name; $rel=@(); foreach($f in $files){$rel += "output/"+$d.Name+"/"+$f.Name}; $arr='["'+($rel -join '","')+'"]'; $first=$rel[0]; $sections += "<details class='topic' open><summary>$($info.title)</summary><div class='desc'><h3>非常詳細主題說明</h3><p>$($info.topic)</p></div><div class='desc anim'><h3>非常詳細動畫說明</h3><p>$($info.anim)</p></div><div class='player' data-frames='$arr'><div class='controls'><button class='prev'>上一張</button><button class='next'>下一張</button><button class='play'>自動播放</button><label>播放速度 <select class='speed'><option value='1800'>慢速</option><option value='1000' selected>正常</option><option value='500'>快速</option></select></label><span class='counter'>1 / $($rel.Count)</span></div><img class='frame' src='$first'></div></details>"; $imgs=""; foreach($r in $rel){$imgs += "<figure><img src='$r'><figcaption>$r</figcaption></figure>"}; $static += "<details class='topic'><summary>$($info.title)</summary><div class='desc'><h3>非常詳細主題說明</h3><p>$($info.topic)</p></div><div class='desc anim'><h3>非常詳細動畫說明</h3><p>$($info.anim)</p></div><div class='grid'>$imgs</div></details>" }
$html="<!doctype html><html lang='zh-Hant'><head><meta charset='utf-8'><title>lec7 Sorting SVG Animation</title><style>$css</style></head><body><header><h1>lec7 Sorting：C++ 產生 SVG 動畫、PowerShell 產生 HTML</h1></header><main>$sections</main><script>$js</script></body></html>"
[IO.File]::WriteAllText((Join-Path $root "index.html"),$html,[Text.UTF8Encoding]::new($true))
$auto="<!doctype html><html lang='zh-Hant'><head><meta charset='utf-8'><title>lec7 all frames</title><style>$css</style></head><body><header><h1>lec7 auto_generated_index：所有 SVG frames</h1></header><main>$static</main></body></html>"
[IO.File]::WriteAllText((Join-Path $root "auto_generated_index.html"),$auto,[Text.UTF8Encoding]::new($true))
